// ---------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------
func buildInsurancesQueryString(filter models.InsuranceFilter) string {
	params := []string{}
	if filter.TransportID.Set {
		params = append(params, "transport_id="+strconv.Itoa(int(filter.TransportID.Value)))
	}
	if filter.InsuranceDateFrom.Set && !filter.InsuranceDateFrom.Value.IsZero() {
		params = append(params, "insurance_from="+filter.InsuranceDateFrom.Value.Format("2006-01-02"))
	}
	if filter.InsuranceDateTo.Set && !filter.InsuranceDateTo.Value.IsZero() {
		params = append(params, "insurance_to="+filter.InsuranceDateTo.Value.Format("2006-01-02"))
	}
	if filter.InsuranceExpirationFrom.Set && !filter.InsuranceExpirationFrom.Value.IsZero() {
		params = append(params, "expiration_from="+filter.InsuranceExpirationFrom.Value.Format("2006-01-02"))
	}
	if filter.InsuranceExpirationTo.Set && !filter.InsuranceExpirationTo.Value.IsZero() {
		params = append(params, "expiration_to="+filter.InsuranceExpirationTo.Value.Format("2006-01-02"))
	}
	if filter.PaymentMin.Set {
		params = append(params, "payment_min="+filter.PaymentMin.Value.String())
	}
	if filter.PaymentMax.Set {
		params = append(params, "payment_max="+filter.PaymentMax.Value.String())
	}
	if filter.CoverageMin.Set {
		params = append(params, "coverage_min="+filter.CoverageMin.Value.String())
	}
	if filter.CoverageMax.Set {
		params = append(params, "coverage_max="+filter.CoverageMax.Value.String())
	}
	if filter.SortBy.Set {
		params = append(params, "sort="+filter.SortBy.Value)
	}
	if filter.SortOrder.Set {
		params = append(params, "order="+filter.SortOrder.Value)
	}
	return strings.Join(params, "&")
}

func buildInsurancesPageURL(baseQuery string, page int) string {
	if baseQuery == "" {
		return fmt.Sprintf("/insurances?page=%d", page)
	}
	return fmt.Sprintf("/insurances?%s&page=%d", baseQuery, page)
}

